import{_ as t,o as s,c as a,a2 as n}from"./chunks/framework.YhErEiPK.js";const p=JSON.parse('{"title":"Using the Stub Runner Boot Application","description":"","frontmatter":{},"headers":[],"relativePath":"reference/stub-runner-spring-boot.md","filePath":"reference/stub-runner-spring-boot.md"}'),o={name:"reference/stub-runner-spring-boot.md"};function i(r,e,l,u,c,h){return s(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="using-the-stub-runner-boot-application" tabindex="-1">Using the Stub Runner Boot Application <a class="header-anchor" href="#using-the-stub-runner-boot-application" aria-label="Permalink to &quot;Using the Stub Runner Boot Application&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Due to limitations in the current artifact repository release tool, we cannot currently release executable jars and as of <code>4.1.6</code> we are skipping the release of this artifact. Stub Runner Boot is still available through the <a href="./docker.html">Docker Stub Runner Boot image</a>, which is the preferred way of using the app. You can also access <a href="https://github.com/stubborn-sh/stubborn-contract/tree/main/stubborn-stub-runner-boot" target="_blank" rel="noreferrer">the sources in the project repository</a> and build the app yourself. If the required adjustments are made in the artifact repository tooling, we&#39;ll resume publishing this jar.</p></div><p>Stubborn Contract Stub Runner Boot is a Spring Boot application that exposes REST endpoints to trigger the messaging labels and to access WireMock servers.</p><h2 id="stub-runner-boot-security" tabindex="-1">Stub Runner Boot Security <a class="header-anchor" href="#stub-runner-boot-security" aria-label="Permalink to &quot;Stub Runner Boot Security&quot;">​</a></h2><p>The Stub Runner Boot application is not secured by design — securing it would require adding security to all stubs even if they don&#39;t actually require it. Since this is a testing utility, the server is <strong>not intended</strong> to be used in production environments.</p><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p>It is expected that <strong>only a trusted client</strong> has access to the Stub Runner Boot server. You should not run this application as a Fat Jar or a <a href="./docker.html">Docker Image</a> in untrusted locations.</p></div><h2 id="stub-runner-server" tabindex="-1">Stub Runner Server <a class="header-anchor" href="#stub-runner-server" aria-label="Permalink to &quot;Stub Runner Server&quot;">​</a></h2><p>To use the Stub Runner Server, add the following dependency:</p><div class="language-groovy vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">groovy</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">compile </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;sh.stubborn:stubborn-starter-contract-stub-runner&quot;</span></span></code></pre></div><p>Then annotate a class with <code>@EnableStubRunnerServer</code>, build a fat jar, and it is ready to work.</p><h2 id="stub-runner-server-fat-jar" tabindex="-1">Stub Runner Server Fat Jar <a class="header-anchor" href="#stub-runner-server-fat-jar" aria-label="Permalink to &quot;Stub Runner Server Fat Jar&quot;">​</a></h2><p>You can download a standalone JAR from Maven by running the following commands:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wget</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -O</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stub-runner.jar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;https://search.maven.org/remotecontent?filepath=sh/stubborn/stubborn-stub-runner-boot/2.0.1.RELEASE/stubborn-stub-runner-boot-2.0.1.RELEASE.jar&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -jar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stub-runner.jar</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --spring.cloud.contract.stubrunner.ids=...</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --spring.cloud.contract.stubrunner.repositoryRoot=...</span></span></code></pre></div><h2 id="spring-cloud-cli" tabindex="-1">Spring Cloud CLI <a class="header-anchor" href="#spring-cloud-cli" aria-label="Permalink to &quot;Spring Cloud CLI&quot;">​</a></h2><p>Starting from the <code>1.4.0.RELEASE</code> version of the <a href="https://cloud.spring.io/spring-cloud-cli" target="_blank" rel="noreferrer">Spring Cloud CLI</a> project, you can start Stub Runner Boot by running <code>spring cloud stubrunner</code>.</p><p>To pass the configuration, you can create a <code>spring.cloud.contract.stubrunner.yml</code> file in the current working directory, in a subdirectory called <code>config</code>, or in <code>~/.spring-cloud</code>. The file could resemble the following example for running stubs installed locally:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">spring.cloud.contract.stubrunner</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  stubsMode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">LOCAL</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  ids</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">com.example:beer-api-producer:+:9876</span></span></code></pre></div><p>Then you can call <code>spring cloud stubrunner</code> from your terminal window to start the Stub Runner server. It is available at port <code>8750</code>.</p><h2 id="endpoints" tabindex="-1">Endpoints <a class="header-anchor" href="#endpoints" aria-label="Permalink to &quot;Endpoints&quot;">​</a></h2><p>Stub Runner Boot offers two sets of endpoints:</p><h3 id="http" tabindex="-1">HTTP <a class="header-anchor" href="#http" aria-label="Permalink to &quot;HTTP&quot;">​</a></h3><p>For HTTP, Stub Runner Boot makes the following endpoints available:</p><ul><li><code>GET /stubs</code>: Returns a list of all running stubs in <code>ivy:integer</code> notation</li><li><code>GET /stubs/{ivy}</code>: Returns a port for the given <code>ivy</code> notation (when calling the endpoint <code>ivy</code> can also be <code>artifactId</code> only)</li></ul><h3 id="messaging" tabindex="-1">Messaging <a class="header-anchor" href="#messaging" aria-label="Permalink to &quot;Messaging&quot;">​</a></h3><p>For Messaging, Stub Runner Boot makes the following endpoints available:</p><ul><li><code>GET /triggers</code>: Returns a list of all running labels in <code>ivy : [label1, label2 ...]</code> notation</li><li><code>POST /triggers/{label}</code>: Runs a trigger with <code>label</code></li><li><code>POST /triggers/{ivy}/{label}</code>: Runs a trigger with a <code>label</code> for the given <code>ivy</code> notation (when calling the endpoint, <code>ivy</code> can also be <code>artifactId</code> only)</li></ul><h2 id="stub-runner-boot-with-service-discovery" tabindex="-1">Stub Runner Boot with Service Discovery <a class="header-anchor" href="#stub-runner-boot-with-service-discovery" aria-label="Permalink to &quot;Stub Runner Boot with Service Discovery&quot;">​</a></h2><p>One way to use Stub Runner Boot is to use it as a feed of stubs for &quot;smoke tests&quot;. What does that mean? Assume that you do not want to deploy 50 microservices to a test environment in order to see whether your application works. You have already run a suite of tests during the build process, but you would also like to ensure that the packaging of your application works. You can deploy your application to an environment, start it, and run a couple of tests on it to see whether it works. We can call those tests &quot;smoke tests&quot;, because their purpose is to check only a handful of testing scenarios.</p><p>The problem with this approach is that, if you use microservices, you most likely also use a service discovery tool. Stub Runner Boot lets you solve this issue by starting the required stubs and registering them in a service discovery tool.</p><p>Now assume that we want to start this application so that the stubs get automatically registered. We can do so by running the application with <code>java -jar \${SYSTEM_PROPS} stub-runner-boot-eureka-example.jar</code>.</p><p>That way, your deployed application can send requests to started WireMock servers through service discovery. Most likely, the basic properties could be set by default in <code>application.yml</code>, because they are not likely to change. That way, you can provide only the list of stubs to download whenever you start the Stub Runner Boot.</p>`,31)])])}const b=t(o,[["render",i]]);export{p as __pageData,b as default};
